Scripts.OnDragStart:
if getglobal('TWTMainLockButtonNT'):GetTexture() == 'Interface\\addons\\TWThreat\\images\\icon_unlocked' then
this:StartMoving();
this.isMoving = true;
end

Scripts.OnDragStop:
this:StopMovingOrSizing();
this.isMoving = false;
TWT_CONFIG.windowPoint[4], TWT_CONFIG.windowPoint[5] = this:GetCenter()

Scripts.OnEnter:
GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('打开设置窗口');
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('锁定/解锁窗口')
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('关闭窗口');
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('Close Window');
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('进入战斗显示');
GameTooltip:AddLine('进入战斗后自动显示仇恨窗口。', 1, 1, 1);
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
