GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
GameTooltip:AddLine('坦克模式');
GameTooltip:AddLine('生成一个额外的窗口，用来显示你周围的怪物仇恨。', 1, 1, 1);
GameTooltip:AddLine('坦克模式会禁用全屏发光效果和仇恨警告音效。', 1,1,1);
GameTooltip:AddLine('只有当你做坦克时，这个框架才会显示。', 1, 1, 1);
GameTooltip:AddLine('会显示多个怪物的仇恨。', 1, 1, 1);
GameTooltip:Show();

GameTooltip:ClearLines();
GameTooltip:SetOwner(this, "ANCHOR_RIGHT", -(this:GetWidth() / 2) + 5, 0);
